// src/pages/bank/TransferPage.jsx
import { useState }  from "react";
import { useToast }  from "../../context/ToastContext";
import PageHeader    from "../../components/shared/PageHeader";
import DataTable     from "../../components/shared/DataTable";
import { donations } from "../../data/mockData";

const fmt = (n) => n?.toLocaleString() ?? "–";

export default function TransferPage() {
  const toast = useToast();
  const [form, setForm] = useState({ from:"", to:"", amount:"", note:"" });
  const upd = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  return (
    <div>
      <PageHeader title="Transfer Tokens" desc="Move tokens between wallets on the ledger" />
      <div className="grid-2">
        <div className="card">
          <div className="form-grid section-gap">
            <div className="form-group"><label>From Wallet</label><input value={form.from} onChange={upd("from")} placeholder="0x..." /></div>
            <div className="form-group"><label>To Wallet</label><input value={form.to} onChange={upd("to")} placeholder="0x..." /></div>
            <div className="form-group"><label>Amount</label><input value={form.amount} onChange={upd("amount")} type="number" placeholder="Token amount" /></div>
            <div className="form-group"><label>Transfer Note</label><textarea value={form.note} onChange={upd("note")} placeholder="Reason for transfer..." /></div>
            <div className="form-actions">
              <button className="btn btn-secondary">Clear</button>
              <button className="btn btn-primary" onClick={() => toast("Transfer submitted to ledger", "success")}>Submit Transfer ⇄</button>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>Recent Transfers</div>
          <DataTable
            columns={[
              { key:"id",     label:"ID",     mono:true },
              { key:"donor",  label:"From"   },
              { key:"fund",   label:"To Fund" },
              { key:"amount", label:"Amount", render:(r) => <span className="text-gold">{fmt(r.amount)}</span> },
              { key:"date",   label:"Date",   mono:true },
            ]}
            data={donations.slice(0, 2)}
          />
        </div>
      </div>
    </div>
  );
}
